import {
  Box,
  Button,
  Flex,
  Input,
  Select,
  Text,
  Table,
  Thead,
  Tbody,
  Tr,
  Th,
  Td,
  Image,
} from "@chakra-ui/react";
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";

import TeacherNavTop from "./TeacherNavTop";
import Pagination from "../Adminitems/Pagination";

import convertDateFormat, {
  getProduct,
} from "../../Redux/TeacherReducer/action";

const AddTeacher = () => {
  const store = useSelector((store) => store.TeacherReducer.data);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const [page, setPage] = useState(1);
  const [search, setSearch] = useState("");
  const [order, setOrder] = useState("");

  const limit = 4;

  useEffect(() => {
    dispatch(getProduct(page, limit, search, order));
  }, [page, search, order]);

  const handleVideos = (id, title) => {
    navigate(`/Teacher/videos/add/${id}`, { state: { id, title } });
  };

  return (
    <>
      <TeacherNavTop />

      <Box bg="#f7f9fa" minH="100vh" p={6}>
        <Box maxW="1100px" mx="auto">
          
          {/* HEADER */}
          <Flex justify="space-between" align="center" mb={6}>
            <Text fontSize="2xl" fontWeight="bold">
              Your Courses
            </Text>

            <Button
              bg="#A435F0"
              color="white"
              _hover={{ bg: "#8710d8" }}
              onClick={() => navigate("/Teacher/addCourse")}
            >
              Create Course
            </Button>
          </Flex>

          {/* FILTER */}
          <Flex gap={4} mb={6} flexWrap="wrap">
            <Input
              placeholder="Search courses..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              maxW="300px"
              bg="white"
            />

            <Select
              placeholder="Sort by price"
              onChange={(e) => setOrder(e.target.value)}
              maxW="200px"
              bg="white"
            >
              <option value="asc">Low → High</option>
              <option value="desc">High → Low</option>
            </Select>
          </Flex>

          {/* TABLE */}
          <Box bg="white" borderRadius="lg" boxShadow="sm" overflow="hidden">
            <Table>
              <Thead bg="#f1f3f5">
                <Tr>
                  <Th>Course</Th>
                  <Th>Category</Th>
                  <Th>Price</Th>
                  <Th>Date</Th>
                  <Th>Action</Th>
                </Tr>
              </Thead>

              <Tbody>
                {store?.map((el) => (
                  <Tr key={el._id} _hover={{ bg: "#f7f9fa" }}>
                    
                    {/* COURSE */}
                    <Td>
                      <Flex align="center" gap={3}>
                        <Image
                          src={el.img}
                          boxSize="50px"
                          borderRadius="md"
                          objectFit="cover"
                        />
                        <Box>
                          <Text fontWeight="bold">{el.title}</Text>
                          <Text fontSize="xs" color="gray.500">
                            {el.teacher}
                          </Text>
                        </Box>
                      </Flex>
                    </Td>

                    <Td>{el.category}</Td>
                    <Td>₹{el.price}</Td>
                    <Td>{convertDateFormat(el.createdAt)}</Td>

                    {/* ACTION */}
                    <Td>
                      <Button
                        size="sm"
                        bg="#A435F0"
                        color="white"
                        _hover={{ bg: "#8710d8" }}
                        onClick={() => handleVideos(el._id, el.title)}
                      >
                        Add Videos
                      </Button>
                    </Td>
                  </Tr>
                ))}
              </Tbody>
            </Table>
          </Box>

          {/* PAGINATION */}
          <Flex justify="center" mt={6} gap={2}>
            <Button
              onClick={() => setPage((p) => p - 1)}
              isDisabled={page === 1}
            >
              Prev
            </Button>

            <Pagination
              totalCount={4}
              current_page={page}
              handlePageChange={setPage}
            />

            <Button onClick={() => setPage((p) => p + 1)}>
              Next
            </Button>
          </Flex>
        </Box>
      </Box>
    </>
  );
};

export default AddTeacher;
